class Admin::DashboardController < Admin::BaseController

  def index
    authorize :admin_dashboard, :index?

    @total_leads = Lead.count
    @total_sdrs = User.sdrs.count
    @active_sdrs = User.active_sdrs.count
    @total_calls = CallSession.finished.count
    @total_imports = Import.count
    @pending_imports = Import.pending.count
    
    @recent_activity = AuditLog.order(created_at: :desc).limit(10)
    
    @statistics = StatisticsService.overall_statistics
  end

  helper_method :activity_icon, :activity_description

  private

  def activity_icon(action)
    icons = {
      login:              '<svg xmlns="http://www.w3.org/2000/svg" class="h-5 w-5 text-green-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M11 16l-4-4m0 0l4-4m-4 4h14m-5 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h7a3 3 0 013 3v1" /></svg>',
      logout:             '<svg xmlns="http://www.w3.org/2000/svg" class="h-5 w-5 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" /></svg>',
